sql:
SELECT model, COUNT(*) AS number_of_turbines
FROM wind_turbines
GROUP BY model;

SELECT wind_farm_name, SUM(capacity_mw) AS total_capacity_mw
FROM wind_farms
GROUP BY wind_farm_name;

SELECT COUNT(*) 
FROM wind_turbines 
WHERE next_maintenance_due <= '2023-05-01';

SELECT AVG(ml.duration_minutes) AS avg_maintenance_duration
FROM maintenance_logs ml
WHERE ml.timestamp > '2023-01-01';

